VALUES
  ('heelevel3-988e0de1-moex-00069', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '依據審計準則之規定，下列與顯著風險有關之敘述何者錯誤？', '["查核人員就收入認列通常應先假設存有顯著風險", "查核人員在評估顯著風險前應先測試相關控制是否有效", "會計估計如涉及管理階層主觀判斷，且估計結果具高度不確定性，此等會計估計可能存有顯著 風險", "受查者之非正常營運之重大關係人交易應評估為顯著風險"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00070', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '甲公司主要係從事汽車銷售業務之上市公司，該公司2018年、2019年及2020年度銷貨收入分別 為50億、53億、38億元，稅前淨利分別為2.5億、3億及0.2億元，2020年度獲利衰退主要原 因係因受新型冠狀病毒疫情之影響，導致甲公司產品銷售量不足，甲公司認為等疫情結束，2021 年度以後應該能逐漸恢復2018年及2019年度之銷售量。會計師查核2018年及2019年度財務報 表於決定財務報表整體重大性係採用稅前淨利為基準，會計師針對 2020 年度查核如何決定適當 基準？', '["採用2018年、2019年及2020年度稅前淨利之平均數", "採用2018年、2019年及2020年度銷貨收入金額之平均數", "採用2020年度稅前淨利", "採用2020年度銷貨收入金額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00071', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '集團查核團隊對組成個體財務資訊擬執行工作類型之決定，下列何者為正確之事項考量優先次', '["對非重要組成個體之財務資訊，執行分析性程序", "所規劃之範圍是否可取足夠及適切之 查核證據，以作為表示集團查核意見之依據", "組成個體是否具有個別財務重要性", "組成個體是 否因其特殊性質或情況，可能存有導致集團財務報表重大不實表達之顯著風險 ⑤對進一步所選 擇之非重要組成個體，執行工作類型"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00072', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '依據審計準則580號（原審計準則公報第六十六號）「書面聲明」之規定，下列有關受查者所出 具之書面聲明何者錯誤？', '["書面聲明之日期應儘量接近查核報告日，但不得晚於該日。書面聲明應涵蓋查核報告中提及之 所有財務報表與期間", "基於管理階層對查核案件條款中所述責任之認知與瞭解，管理階層對其認知與瞭解之再次確 認，可使用「就本公司所知」之限制性文字", "現任管理階層於查核報告中提及之所有期間可能並非均在職，於此情況下，查核人員仍須向現 任管理階層取得涵蓋所有期間之書面聲明", "查核人員對管理階層之誠信有重大懷疑，致其認為所取得之書面聲明並不可靠時，會計師應對 財務報表出具無法表示意見之查核報告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00073', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '下列何種情況最不可能影響對查核風險之判斷？', '["受查公司即將首次公開發行股票", "受查公司未於財務報表揭露關係人交易", "受查公司之會計部門主管流動率高", "受查公司每兩週即發一次員工薪水"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00074', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '針對受查者20X1年12月31日之所有銷貨收入執行認列時點之查核程序，查核人員發現有一筆 銷貨之交易條件約定為目的地交貨，買方係於 20X2 年 1 月 3 日簽收，但受查公司會計人員於 20X1年12月31日出貨後即認列收入，則該不實表達為：', '["實際不實表達", "判斷性不實表達", "推估不實表達", "預期不實表達"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00075', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '下列有關查核人員於查核財務報表時，對期後事項應負之責任的敘述，何者錯誤？', '["查核人員應執行適當之查核程序，俾對財務報導期間結束日後至查核報告日間所發生須於財務 報表中調整或揭露之事項是否均已辨認，取得足夠及適切之查核證據", "查核人員應執行適當之查核程序，俾對財務報導期間結束日後至財務報表發布日間所發生須於 財務報表中調整或揭露之事項是否均已辨認，取得足夠及適切之查核證據", "查核人員應要求管理階層針對財務報導期間結束日後發生且依編製財務報表所依據之準則須 調整或揭露之事項均已調整或揭露，出具書面聲明", "查核人員對於查核報告日後始獲悉之事實，該等事實若查核人員於查核報告日即獲悉可能導致 其修改查核報告，有查核之義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00076', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '依據審計準則260號（原審計準則公報第六十二號）「與受查者治理單位之溝通」之規定，查核 人員查核非上市櫃公司財務報表時，與受查者治理單位之溝通的事項得不包括下列何者？', '["查核人員查核財務報表之責任", "所規劃之查核範圍與時間之概要", "查核之重大發現", "查核人員之獨立性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00077', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '有關X1年12月31日應收帳款函證之回函資訊，會計師通常最關注下列何者？', '["賒購商品客戶已於X1年12月15日退回", "應收帳款金額已於X1年12月31日付訖", "客戶於X2年1月2日收到商品", "應收帳款餘額尚未扣除受查者於X2年1月2日同意給予之銷貨折扣"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00078', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '查核人員發現某公司的付款政策為收到請款通知後兩個月才進行付款，且由系統進行控制；另外，查 核人員同時以分析性程序計算本年度應付帳款週轉率為8次，依此研判最可能的情形是下列何者？', '["出納人員延遲付款", "應付帳款低估", "本期進貨低估", "應付帳款高估"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL)
